#!/usr/bin/env node
// LinkedIn Groups Helper.
//
// LinkedIn deprecated the Groups API in 2018. There is NO way to auto-post to
// groups via API in 2026 (only LinkedIn Marketing Partners with special status
// can). This script generates a curated list of relevant groups + a shareable
// post link so YOU can manually share to each group in one click.
//
// Workflow:
//   1. Bot auto-posts to your personal feed (linkedin-auto-post.mjs)
//   2. Bot generates docs/launch/LINKEDIN_GROUPS_TO_SHARE.md
//   3. You open each group, click Share → paste your post URL → submit (30s/group)

import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname } from 'node:path';

const STATE_PATH = '.github/.linkedin-post-state.json';
const REPORT_PATH = 'docs/launch/LINKEDIN_GROUPS_TO_SHARE.md';

// Curated list of relevant LinkedIn groups by topic.
// Member counts are approximate — adjust based on what you find.
// You'll need to JOIN these groups first (one-time, free).
const GROUPS = [
  // AI / Machine Learning (huge audiences)
  { name: 'Artificial Intelligence and Machine Learning', members: '4M+', search: 'Artificial Intelligence and Machine Learning' },
  { name: 'Artificial Intelligence', members: '2M+', search: 'Artificial Intelligence' },
  { name: 'Machine Learning Community', members: '500K+', search: 'Machine Learning Community' },
  { name: 'AI & Generative AI Community', members: '300K+', search: 'AI Generative AI Community' },

  // AI Coding / Developer Tools
  { name: 'Generative AI for Developers', members: '200K+', search: 'Generative AI for Developers' },
  { name: 'AI Engineers', members: '100K+', search: 'AI Engineers' },
  { name: 'LLM Engineers and Practitioners', members: '50K+', search: 'LLM Engineers' },

  // Open Source / Software Engineering
  { name: 'Open Source Developers', members: '500K+', search: 'Open Source Developers' },
  { name: 'JavaScript Developers Group', members: '700K+', search: 'JavaScript Developers' },
  { name: 'TypeScript Developers', members: '200K+', search: 'TypeScript Developers' },
  { name: 'Node.js Developers', members: '300K+', search: 'Node.js Developers' },

  // Specific AI Tools
  { name: 'Claude AI Users', members: '50K+', search: 'Claude AI Users' },
  { name: 'Cursor IDE Community', members: '20K+', search: 'Cursor IDE' },
  { name: 'GitHub Copilot Users', members: '40K+', search: 'GitHub Copilot' },

  // Startups / Product
  { name: 'Product Hunt Community', members: '600K+', search: 'Product Hunt' },
  { name: 'Indie Hackers', members: '400K+', search: 'Indie Hackers' },
  { name: 'Solo Founders / Solopreneurs', members: '200K+', search: 'Solo Founders' },
];

// Read last post URL from state (if available)
let postUrl = '';
let lastPostAt = null;
if (existsSync(STATE_PATH)) {
  try {
    const state = JSON.parse(readFileSync(STATE_PATH, 'utf-8'));
    postUrl = state.lastPostUrl || '';
    lastPostAt = state.lastPostAt || null;
  } catch { /* skip */ }
}

const md = `# LinkedIn Groups — Manual Share Checklist

_Auto-generated by the Viral Amplifier Bot. Last refresh: ${new Date().toISOString().slice(0, 10)}._

> ⚠️ **LinkedIn deprecated the Groups API in 2018.** There is NO way to auto-post to groups in 2026. This is a manual share checklist — each share takes ~30 seconds.

${postUrl ? `## Your Latest Post\n\n${postUrl}\n\n_Posted ${lastPostAt ? new Date(lastPostAt).toISOString().slice(0, 16).replace('T', ' ') : 'unknown'} UTC_` : '## ⚠️ No Recent Post Found\n\nRun the LinkedIn auto-post job first (or post manually), then re-run this script to populate share targets.'}

---

## How to Share to a Group (30 seconds per group)

1. Click the group link below
2. If you're not a member, click **Request to Join** (one-time, takes a day or two for approval)
3. Once a member, click the **+** or **Start a post** button at the top of the group
4. Paste your post URL (above) — LinkedIn will auto-embed it as a rich preview
5. Add a 1-sentence comment about why this group will care (optional but boosts engagement)
6. Click **Post**

## Anti-Spam Rules (LinkedIn enforces these)

- **DON'T** share to >5 groups in a single hour — looks like spam
- **DON'T** post identical text to multiple groups — write a unique 1-line intro per group
- **DON'T** post the same URL to the same group within 30 days
- **DO** wait at least a week between sharing to the same group
- **DO** engage with comments after posting (replies > likes for the algorithm)

---

## Recommended Groups (in priority order — biggest audience first)

${GROUPS.map((g, i) => `### ${i + 1}. ${g.name}

- **Members:** ${g.members}
- **Search link:** [Find on LinkedIn](https://www.linkedin.com/search/results/groups/?keywords=${encodeURIComponent(g.search)})
- **Why this group:** ${groupRationale(g.name)}
${postUrl ? `- **Custom intro suggestion:** "${customIntro(g.name)}"` : ''}
`).join('\n')}

---

## Suggested Posting Schedule (over 7 days)

To avoid LinkedIn's spam filter, space out your shares:

- **Day 1 (after auto-post):** 3 most relevant groups (Generative AI for Developers, LLM Engineers, AI Engineers)
- **Day 2:** 2 mid-priority groups (Open Source Developers, Node.js Developers)
- **Day 3:** Skip — let engagement breathe
- **Day 4:** 2 more groups (TypeScript Developers, Claude AI Users)
- **Day 5:** Skip
- **Day 6:** 2 final groups (Indie Hackers, Solo Founders)
- **Day 7:** Skip — full week to let post mature

Total reach via groups: 5-10M+ members (depending on group activity)

---

## Track What Works

After 14 days, note which groups gave the most engagement (likes, comments, repost). Update this list to deprioritize the dead ones.

\`\`\`bash
# Re-run this script anytime to refresh the checklist
node .github/scripts/linkedin-groups-helper.mjs
\`\`\`
`;

function groupRationale(name) {
  if (name.includes('AI') || name.includes('Machine')) return 'AI/ML practitioners building real-world tools — your core audience';
  if (name.includes('Open Source')) return 'Devs who star and share open-source projects';
  if (name.includes('JavaScript') || name.includes('TypeScript') || name.includes('Node')) return 'Your stack — TypeScript/Node devs likely to install';
  if (name.includes('Claude') || name.includes('Cursor') || name.includes('Copilot')) return 'Direct user community for the tools your project augments';
  if (name.includes('Indie') || name.includes('Solo') || name.includes('Product Hunt')) return 'Solo builders who appreciate solo-built projects';
  return 'Relevant developer audience';
}

function customIntro(name) {
  if (name.includes('AI') || name.includes('Machine')) return 'Sharing this with the AI builder community — solves a memory-fragmentation problem when using multiple AI coding tools.';
  if (name.includes('Open Source')) return 'New open-source release — would love feedback from this community.';
  if (name.includes('JavaScript') || name.includes('TypeScript') || name.includes('Node')) return 'Built in TypeScript with zero new runtime deps — sharing for the JS/TS folks here.';
  if (name.includes('Claude')) return 'For Claude Code users — this gives Claude shared memory with your other AI tools.';
  if (name.includes('Cursor')) return 'For Cursor users who also use other AI tools — this shares context across all of them.';
  if (name.includes('Copilot')) return 'For Copilot users who augment with other AI assistants — this layer keeps them all in sync.';
  if (name.includes('Indie') || name.includes('Solo')) return 'Solo-built, MIT, no-config — sharing for fellow indie folks.';
  if (name.includes('Product Hunt')) return 'Considering a PH launch — would love early feedback from this community first.';
  return 'Sharing this open-source project that might be relevant for the group.';
}

mkdirSync(dirname(REPORT_PATH), { recursive: true });
writeFileSync(REPORT_PATH, md);
console.log(`LinkedIn groups checklist written: ${GROUPS.length} groups.`);
console.log(`Report at ${REPORT_PATH}`);
